// agendaItem is one entry in the unified day view. It carries enough to sort
// chronologically and render either as a human line or as JSON.
type agendaItem struct {
	Type  string `json:"type"`            // "event" or "task"
	Title string `json:"title"`           // event/task title
	Time  string `json:"time,omitempty"`  // local time "15:04", empty for all-day/no-time
	When  string `json:"when,omitempty"`  // raw ISO timestamp from the API
	ID    string `json:"id"`              // source event/task id
}

// agendaResult is the JSON envelope returned by `agenda`.
type agendaResult struct {
	Date  string       `json:"date"`
	Items []agendaItem `json:"items"`
}

// calendarsEnvelope mirrors GET /calendars/list. Calendars are a flat array
// under data.calendars, each tagged with the accountId it belongs to.
type calendarsEnvelope struct {
	Data struct {
		Accounts []struct {
			ID string `json:"id"`
		} `json:"accounts"`
		Calendars []struct {
			ID        string `json:"id"`
			AccountID string `json:"accountId"`
			Name      string `json:"name"`
		} `json:"calendars"`
	} `json:"data"`
}

// eventsEnvelope mirrors GET /events/list. Morgen returns start as a local
// ISO timestamp (no zone) and flags all-day items with showWithoutTime.
type eventsEnvelope struct {
	Data struct {
		Events []struct {
			ID              string `json:"id"`
			Title           string `json:"title"`
			Start           string `json:"start"`
			ShowWithoutTime bool   `json:"showWithoutTime"`
		} `json:"events"`
	} `json:"data"`
}

// tasksEnvelope mirrors GET /tasks/list. Tasks carry a `due` ISO timestamp
