func newAgendaCmd(flags *rootFlags) *cobra.Command {
	var flagDate string
	var flagAccountID string
	var flagCalendarIds string

	cmd := &cobra.Command{
		Use:   "agenda",
		Short: "Unified chronological day view: calendar events + tasks due, merged and sorted",
		Long: `Build a single chronological view of your day by joining two sources the
Morgen API never returns together: calendar events and tasks due that day.

Calendars are auto-discovered from /calendars/list, so no IDs are required.
Use --date to pick a day (default today), and --account-id / --calendar-ids
to scope the events side.`,
		Example: "  morgen-pp-cli agenda\n  morgen-pp-cli agenda --date 2026-06-16\n  morgen-pp-cli agenda --account-id 6a2f29ad82416825aa4f60b2 --agent",
		Annotations: map[string]string{"mcp:read-only": "true", "pp:data-source": "live"},
		RunE: func(cmd *cobra.Command, args []string) error {
			// Resolve the target day in local time.
			day := time.Now()
			if flagDate != "" {
				parsed, err := time.ParseInLocation("2006-01-02", flagDate, time.Local)
				if err != nil {
					return usageErr(fmt.Errorf("invalid --date %q: expected YYYY-MM-DD", flagDate))
				}
				day = parsed
			}
			dayStr := day.Format("2006-01-02")

			if dryRunOK(flags) {
				return nil
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}

			// 1. Discover calendars grouped by account.
			calData, err := c.Get("/calendars/list", nil)
			if err != nil {
				return classifyAPIError(err, flags)
			}
			var cals calendarsEnvelope
			if err := json.Unmarshal(calData, &cals); err != nil {
				return apiErr(fmt.Errorf("parsing calendars response: %w", err))
			}

			// Optional scoping: restrict to a single account and/or an
			// explicit set of calendar ids.
			wantCal := map[string]bool{}
			if flagCalendarIds != "" {
				for _, id := range strings.Split(flagCalendarIds, ",") {
					id = strings.TrimSpace(id)
					if id != "" {
						wantCal[id] = true
					}
				}
			}
			calsByAccount := map[string][]string{}
			for _, cal := range cals.Data.Calendars {
				if flagAccountID != "" && cal.AccountID != flagAccountID {
					continue
				}
				if len(wantCal) > 0 && !wantCal[cal.ID] {
					continue
				}
				calsByAccount[cal.AccountID] = append(calsByAccount[cal.AccountID], cal.ID)
			}

			// Fetch a padded UTC window (day-1 .. day+2) so timezone offsets
			// between the local day and Morgen's UTC bounds can't drop
			// local-evening or early-morning events. We filter precisely to the
			// local day client-side below.
			start := day.AddDate(0, 0, -1).Format("2006-01-02") + "T00:00:00Z"
			end := day.AddDate(0, 0, 2).Format("2006-01-02") + "T00:00:00Z"

			items := []agendaItem{}

			// 2. Events: one /events/list call per account with its calendars.
			for accountID, calIDs := range calsByAccount {
				if len(calIDs) == 0 {
					continue
				}
				params := map[string]string{
					"accountId":   accountID,
					"calendarIds": strings.Join(calIDs, ","),
					"start":       start,
					"end":         end,
				}
				evData, err := c.Get("/events/list", params)
				if err != nil {
					return classifyAPIError(err, flags)
				}
				var evs eventsEnvelope
				if err := json.Unmarshal(evData, &evs); err != nil {
					return apiErr(fmt.Errorf("parsing events response: %w", err))
				}
				for _, e := range evs.Data.Events {
					// Keep only events that start on the chosen local day. The
					// padded fetch window above returns neighbors and multi-day
					// spans; this prefix-on-local-date check (same as tasks)
					// keeps the view to the day the user asked for.
					if !sameDay(e.Start, dayStr) {
						continue
					}
					it := agendaItem{Type: "event", Title: e.Title, When: e.Start, ID: e.ID}
					if !e.ShowWithoutTime {
						it.Time = timeOfDay(e.Start)
					}
					items = append(items, it)
				}
			}

			// 3. Tasks: fetch all, keep those due on the chosen day.
			taskData, err := c.Get("/tasks/list", nil)
			if err != nil {
				return classifyAPIError(err, flags)
			}
			var tasks tasksEnvelope
			if err := json.Unmarshal(taskData, &tasks); err != nil {
				return apiErr(fmt.Errorf("parsing tasks response: %w", err))
			}
			for _, t := range tasks.Data.Tasks {
				if t.Due == "" || !sameDay(t.Due, dayStr) {
					continue
				}
				items = append(items, agendaItem{
					Type:  "task",
					Title: t.Title,
					Time:  timeOfDay(t.Due),
					When:  t.Due,
					ID:    t.ID,
				})
			}

			// Sort chronologically: all-day / no-time items first, then by
			// time of day, with a stable title tiebreaker.
			sort.SliceStable(items, func(i, j int) bool {
				ti, tj := items[i].Time, items[j].Time
				if ti != tj {
					return ti < tj // "" (all-day) sorts before any "HH:MM"
				}
				return items[i].Title < items[j].Title
			})

			result := agendaResult{Date: dayStr, Items: items}

			// JSON output for --json / --agent / non-TTY consumers.
			if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
				raw, mErr := json.Marshal(result)
				if mErr != nil {
					return mErr
				}
				return printOutput(cmd.OutOrStdout(), json.RawMessage(raw), true)
			}

			// Human-readable list.
			fmt.Fprintf(cmd.OutOrStdout(), "%s\n", bold(dayStr))
			if len(items) == 0 {
				fmt.Fprintln(cmd.OutOrStdout(), "  (nothing scheduled)")
				return nil
			}
			tw := newTabWriter(cmd.OutOrStdout())
			for _, it := range items {
				when := it.Time
				if when == "" {
					when = "all-day"
				}
				fmt.Fprintf(tw, "%s\t%s\t%s\n", when, strings.ToUpper(it.Type), it.Title)
			}
			return tw.Flush()
		},
	}

	cmd.Flags().StringVar(&flagDate, "date", "", "Day to show (YYYY-MM-DD, default: today)")
	cmd.Flags().StringVar(&flagAccountID, "account-id", "", "Limit events to a single calendar account ID")
	cmd.Flags().StringVar(&flagCalendarIds, "calendar-ids", "", "Comma-separated calendar IDs to include (default: all)")

	return cmd
}

// timeOfDay extracts "HH:MM" from a Morgen ISO timestamp. Morgen returns
// local wall-clock timestamps (e.g. "2026-06-15T06:15:00", sometimes with a
// trailing Z or offset). We parse leniently and fall back to a substring.
func timeOfDay(iso string) string {
	if iso == "" {
		return ""
	}
	for _, layout := range []string{
		"2006-01-02T15:04:05",
		time.RFC3339,
		"2006-01-02T15:04:05Z07:00",
	} {
		if tm, err := time.Parse(layout, iso); err == nil {
			return tm.Format("15:04")
		}
	}
	// Fallback: pull the HH:MM out of the "T..." segment.
	if i := strings.IndexByte(iso, 'T'); i >= 0 && len(iso) >= i+6 {
		return iso[i+1 : i+6]
	}
	return ""
}

// sameDay reports whether an ISO timestamp falls on the given YYYY-MM-DD date.
// Morgen `due`/`start` values are local wall-clock, so a prefix compare on the
// date portion is the correct, zone-stable check.
func sameDay(iso, dayStr string) bool {
	if len(iso) < 10 {
		return false
	}
	return iso[:10] == dayStr
}
